.progress-bar-shell {
  /* Custom Properties */
  --gauge-width: 420px;
  --gauge-height: 50px;
  --gauge-border-radius: 25px;

  --color-track-bg-start: #e0e0e0;
  --color-track-bg-end: #f0f0f0;
  --color-track-shadow: rgba(0, 0, 0, 0.08);
  --color-track-inset-shadow-light: rgba(255, 255, 255, 0.7);
  --color-track-inset-shadow-dark: rgba(0, 0, 0, 0.15);

  --color-fill-start: #5de2a3; /* Light green from original */
  --color-fill-end: #379e1f;   /* Dark green from original */
  --color-fill-highlight: #80ea69;
  --color-fill-shadow: rgba(77, 200, 143, 0.72); /* Original shadow color */

  --color-indicator-light: #c7ffbc; /* Very light green from original */
  --color-indicator-dark: #379e1f; /* Dark green from original */
  --color-indicator-shadow-main: rgba(77, 200, 143, 0.6);
  --color-indicator-shadow-glow: rgba(77, 200, 143, 0.3);
  --indicator-size: 38px;
  --indicator-shine-size: 14px;

  --color-text: #333;
  --color-text-highlight: var(--color-fill-end);

  --transition-duration: 0.4s;
  --font-family-primary: 'Arial', sans-serif; /* Using a common sans-serif font, similar vibe to Lexend Deca */

  /* Component Styles */
  width: var(--gauge-width);
  height: var(--gauge-height);
  border-radius: var(--gauge-border-radius);
  position: relative;
  overflow: hidden;
  cursor: pointer;
  box-shadow: 0 8px 15px -3px var(--color-track-shadow);
  background: linear-gradient(145deg, var(--color-track-bg-start), var(--color-track-bg-end));
  transition: transform var(--transition-duration) ease-out, box-shadow var(--transition-duration) ease-out;
}

.progress-bar-shell:hover {
  transform: translateY(-5px) scale(1.01);
  box-shadow: 0 12px 20px -5px var(--color-track-shadow);
}

.progress-bar-track {
  position: absolute;
  top: 3px;
  left: 3px;
  right: 3px;
  bottom: 3px;
  border-radius: calc(var(--gauge-border-radius) - 3px);
  background-color: var(--neutral-light-gray);
  box-shadow: inset 0 2px 5px var(--color-track-inset-shadow-dark), 
              inset 0 -2px 5px var(--color-track-inset-shadow-light);
}

.progress-bar-fill {
  position: absolute;
  left: 0;
  top: 0;
  height: 100%;
  width: var(--progress-percentage, 0%); /* Default to 0 if not set */
  border-radius: calc(var(--gauge-border-radius) - 3px);
  background: linear-gradient(to right, var(--color-fill-start), var(--color-fill-end));
  box-shadow: 0 0 10px 0 var(--color-fill-shadow);
  transition: width 1s cubic-bezier(0.25, 1, 0.5, 1), background var(--transition-duration) ease-in-out;
  display: flex;
  align-items: center;
  justify-content: flex-end;
  padding-right: var(--indicator-size);
}

.progress-bar-fill:hover {
  background: linear-gradient(to right, var(--color-fill-start), var(--color-fill-highlight)); /* Slightly lighter end on hover */
}

.progress-fill-indicator {
  position: absolute;
  right: calc((var(--indicator-size) / 2) * -1); /* Center indicator at the end of the fill */
  top: 50%;
  transform: translateY(-50%) scale(1);
  width: var(--indicator-size);
  height: var(--indicator-size);
  border-radius: 50%;
  background: radial-gradient(circle at top left, var(--color-indicator-light) 0%, var(--color-indicator-dark) 100%);
  box-shadow: 
    0 0 0 3px var(--color-indicator-light), /* Outer ring */
    0 0 15px 5px var(--color-indicator-shadow-main), /* Main glow */
    0 0 25px 8px var(--color-indicator-shadow-glow); /* Wider glow */
  transition: transform var(--transition-duration) ease-in-out, box-shadow var(--transition-duration) ease-in-out;
  z-index: 2;
  display: flex;
  justify-content: center;
  align-items: center;
}

.progress-bar-shell:hover .progress-fill-indicator {
  transform: translateY(-50%) scale(1.1);
  box-shadow: 
    0 0 0 4px var(--color-indicator-light), 
    0 0 20px 7px var(--color-indicator-shadow-main), 
    0 0 30px 10px var(--color-indicator-shadow-glow);
}

.indicator-shine {
  width: var(--indicator-shine-size);
  height: var(--indicator-shine-size);
  border-radius: 50%;
  background: rgba(255, 255, 255, 0.8);
  box-shadow: 0 0 10px 3px rgba(255, 255, 255, 0.6);
  opacity: 0;
  transition: opacity var(--transition-duration) ease-in-out;
}

.progress-bar-shell:hover .indicator-shine {
  opacity: 1;
  animation: shine-pulse 1s ease-in-out infinite;
}

@keyframes shine-pulse {
  0%, 100% {
    transform: scale(0.9);
    opacity: 0.8;
  }
  50% {
    transform: scale(1.1);
    opacity: 1;
  }
}

.progress-value {
  font-family: var(--font-family-primary);
  font-size: calc(var(--gauge-height) * 0.4);
  font-weight: 600;
  color: var(--color-text);
  position: absolute;
  right: calc(var(--indicator-size) / 2 + 15px); /* Positioned relative to the end of the fill */
  text-shadow: 0 1px 2px rgba(255, 255, 255, 0.5);
  transition: color var(--transition-duration) ease-in-out, 
              transform var(--transition-duration) ease-in-out, 
              right var(--transition-duration) ease-in-out;
}

.progress-bar-shell:hover .progress-value {
  color: var(--color-text-highlight);
  transform: translateX(-5px);
  right: calc(var(--indicator-size) / 2 + 10px);
}
